// ══════════════════════════════════════════════════════════════════
// CONFIGURAÇÃO DO CLIENTE — edite ao duplicar o workflow
// ══════════════════════════════════════════════════════════════════
const CLIENT = {
  api_url: 'https://interconvertible-submolecular-irena.ngrok-free.dev',  // URL da API via ngrok
  brand_slug: 'legado-viking',       // slug do brand_profiles/*.json
  brand_name: 'Legado Viking • Runas Ancestrais',
  niche: 'cultura viking, runas nórdicas, mitologia nórdica e simbolismo ancestral',
  country: 'BR',                     // BR, US, IT, ES, DE, FR, MX, PT, UK
  cta: 'Descubra seu legado',
  content_type: 'carousel',              // carousel | video | both
  creator: '',                       // estilo de criador (vazio = sem)
  duration: 15,                      // duração do vídeo (seg)
  auto_post: true,                   // true = posta no Instagram, false = só gera
};

return CLIENT;

// ══════════════════════════════════════════════════════════════════
// ROTAÇÃO INTELIGENTE DE TEMAS
// Pega temas frescos da pesquisa + rotaciona em ordem circular
// ══════════════════════════════════════════════════════════════════
const config = $('⚙️ Config do Cliente').item.json;
const research = $input.item.json;

if (!research.ok) {
  throw new Error('Pesquisa falhou: ' + JSON.stringify(research));
}

// Combina temas da pesquisa (frescos) com ângulos
const allTopics = [
  ...(research.topics || []),
  ...(research.angles || []).map(a => a),
];

if (allTopics.length === 0) {
  throw new Error('Nenhum tema encontrado para o nicho: ' + config.niche);
}

// Rotação circular
const staticData = $getWorkflowStaticData('global');
let idx = staticData.topicIndex || 0;
if (idx >= allTopics.length) idx = 0;
const topic = allTopics[idx];
staticData.topicIndex = idx + 1;

const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);

return {
  ...config,
  topic,
  topic_index: idx,
  total_topics: allTopics.length,
  trends: research.trends || [],
  pains: research.pains || [],
  tone: research.tone || '',
  output_dir: `output/${config.brand_slug}_${ts}`,
  execution_id: ts,
};

const copy = $input.item.json;
const vars = $('🎯 Escolher Tema (rotação)').item.json;

if (!copy.ok) {
  throw new Error('Copy falhou: ' + JSON.stringify(copy));
}

return {
  brand_slug: vars.brand_slug,
  brand_name: vars.brand_name,
  niche: vars.niche,
  output_dir: vars.output_dir,
  cta: vars.cta,
  content_type: vars.content_type,
  duration: vars.duration,
  topic: vars.topic,
  auto_post: vars.auto_post,
  copy: {
    formula: copy.formula,
    headline_part1: copy.headline_part1,
    headline_part2: copy.headline_part2,
    caption: copy.caption,
    hashtags: copy.hashtags,
    image_query: copy.image_query,
    video_query: copy.video_query,
    compliance_flags: copy.compliance_flags
  },
  has_compliance_flags: (copy.compliance_flags ?? []).length > 0,
  compliance_summary: (copy.compliance_flags ?? []).join(' | ')
};

// Consolida resultados de carrossel e/ou vídeo
const vars = $('Montar payload').item.json;

let cover_path = null;
let video_path = null;
let slide_paths = [];
let drive_urls = [];

// Tenta ler carrossel (pode não ter executado)
try {
  const c = $('🖼️ Carrossel').item.json;
  if (c && c.ok) {
    cover_path = c.cover_path;
    slide_paths = c.slide_paths ?? [];
    drive_urls = drive_urls.concat(c.drive_urls ?? []);
  }
} catch(e) {
  // Carrossel não executou — OK
}

// Tenta ler vídeo (pode não ter executado)
try {
  const v = $('🎬 Vídeo').item.json;
  if (v && v.ok) {
    video_path = v.video_path;
    drive_urls = drive_urls.concat(v.drive_urls ?? []);
  }
} catch(e) {
  // Vídeo não executou — OK
}

return {
  ...vars,
  cover_path,
  video_path,
  slide_paths,
  drive_urls,
};

const vars = $('Consolidar').item.json;
const copy = vars.copy;

// Monta URLs públicas das imagens (do Drive)
const image_urls = (vars.drive_urls || []).filter(u => u && !u.includes('mp4'));
const video_url = (vars.drive_urls || []).find(u => u && u.includes('mp4')) || null;

return {
  ok: true,
  brand: vars.brand_slug,
  brand_name: vars.brand_name,
  niche: vars.niche,
  topic: vars.topic,
  output_dir: vars.output_dir,
  headline: copy.headline_part1 + ' ' + copy.headline_part2,
  caption: copy.caption,
  hashtags: copy.hashtags,
  cover_path: vars.cover_path,
  video_path: vars.video_path,
  slide_paths: vars.slide_paths,
  drive_urls: vars.drive_urls,
  image_urls,
  video_url,
  auto_post: vars.auto_post,
  compliance_flags: vars.compliance_summary,
  generated_at: new Date().toISOString()
};

const d = $('📊 Resultado Final').item.json;

const msg = [
  d.auto_post ? '📱 PUBLICADO!' : '📦 GERADO!',
  `Brand: ${d.brand_name}`,
  `Tema: ${d.topic}`,
  `Headline: ${d.headline}`,
  `Slides: ${(d.slide_paths ?? []).length}`,
  `Vídeo: ${d.video_path ? '✅' : '—'}`,
  `Ads: ${d.ads?.report_path ? '✅' : '—'}`,
  `Auto-post: ${d.auto_post ? '✅ Instagram' : '❌ Desligado'}`,
  d.drive_urls?.[0] ? `Drive: ${d.drive_urls[0]}` : '',
  d.generated_at,
].filter(Boolean).join('\n');

console.log(msg);
return { notification: msg };

const d = $('📊 Resultado Final').item.json;
let social = {};
try { social = $('📱 Publicar no Instagram').item.json; } catch(e) {}

return {
  timestamp: d.generated_at,
  brand: d.brand,
  topic: d.topic,
  headline: d.headline,
  carousel: (d.slide_paths ?? []).length > 0,
  video: !!d.video_path,
  ads: !!d.ads?.report_path,
  auto_posted: d.auto_post,
  social_results: social,
  drive_urls: d.drive_urls || [],
};
